set(gca,'XTick',[-2,-1.5,-1,-.5,0,.5,1,1.5,2],...
        'YTick',[0,40,80,120],...
        'XTickLabel',{'-2.0';'-1.5';'-1.0';'-0.5';'0';'0.5';'1.0';'1.5';'2.0'},...
        'Fontname', 'arial','FontSize',12,...
        'box','off')

subplot(3,1,3)
histogram(data_cruise,xAux)
hold 
plot(xCruise2,yAux,...
    'Color','k',...
    'LineWidth',2,...
    'LineStyle',':')
plot(xCruise,yAux,...
    'Color',[1,0,0],...
    'LineWidth',2,...
    'LineStyle',':')

title('(c) Non-fishing hours',...
    'Fontname', 'arial','FontSize',16.,...
    'Interpreter', 'latex')
ylabel({'Frequency'},...
    'Fontname', 'arial','FontSize',16,...
    'Interpreter', 'latex')
xlabel({'Coefficients from placebo regressions'},...
    'Fontname', 'arial','FontSize',16,...
